<template><div class="min-h-screen bg-gradient-to-br from-slate-50 to-blue-50/30 p-6"><div class="mb-8"><div class="flex items-center justify-between"><div><h1 class="text-3xl font-bold bg-gradient-to-r from-slate-800 to-blue-600 bg-clip-text text-transparent mb-2">🎁 Promotion Management</h1><p class="text-slate-600 font-light">Manage featured promotions</p></div><button @click="refreshData" class="p-2 hover:bg-white/50 rounded-xl transition-all duration-300"><ArrowPathIcon class="w-6 h-6 text-slate-600" /></button></div></div><div v-if="error" class="bg-rose-50 border border-rose-200 rounded-2xl p-6 mb-6"><div class="flex items-center justify-between"><div class="flex items-center space-x-3"><ExclamationTriangleIcon class="w-6 h-6 text-rose-600" /><div><h3 class="text-rose-800 font-semibold">Failed to load promotion data</h3><p class="text-rose-600 text-sm">{{ error }}</p></div></div><button @click="fetchPromotions" class="px-4 py-2 bg-rose-600 text-white rounded-lg hover:bg-rose-700">Retry</button></div></div><div v-if="loading && !error" class="flex items-center justify-center py-20"><div class="text-center"><div class="relative"><div class="w-16 h-16 border-4 border-blue-200 rounded-full"></div><div class="w-16 h-16 border-4 border-transparent border-t-blue-500 rounded-full animate-spin absolute top-0 left-0"></div></div><p class="mt-4 text-slate-500 font-light">Loading promotions...</p></div></div><div v-else-if="!loading" class="space-y-8"><div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6"><ModernMetricCard title="Total Promotions" :value="stats.total_promotions" icon="🎁" color="blue" :formatted="true" /><ModernMetricCard title="Active" :value="stats.active_promotions" icon="✅" color="emerald" :formatted="true" /><ModernMetricCard title="Total Views" :value="stats.total_views" icon="👁️" color="cyan" :formatted="true" /><ModernMetricCard title="Conversions" :value="stats.total_conversions" icon="🎯" color="purple" :formatted="true" /></div><SearchBar v-model="searchTerm" placeholder="Search promotions..." :filters="filters" @filter-change="handleFilterChange" @clear="clearFilters" @add="openCreateModal" /><DataTable title="Promotion Records" :data="filteredPromotions" :columns="columns" :actions="['edit', 'delete']" @edit="openEditModal" @delete="openDeleteModal"><template #cell-is_active="{ value }"><span :class="value ? 'bg-emerald-100 text-emerald-800' : 'bg-slate-100 text-slate-800'" class="px-2 py-1 text-xs font-medium rounded-full">{{ value ? 'Active' : 'Inactive' }}</span></template></DataTable></div><FormModal :show="showFormModal" title="Promotion" :fields="formFields" :initial-data="selectedPromotion" :loading="saveLoading" @close="closeFormModal" @submit="savePromotion" /><ConfirmDialog :show="showDeleteModal" title="Delete Promotion" :message="`Delete promotion <strong>${promotionToDelete?.name}</strong>?`" type="danger" :loading="deleteLoading" @confirm="confirmDelete" @cancel="closeDeleteModal" /></div></template><script>import { ref, computed, onMounted } from 'vue';import { useApi } from '../composables/useApi';import ModernMetricCard from '../components/MetricCard.vue';import SearchBar from '../components/SearchBar.vue';import DataTable from '../components/DataTable.vue';import FormModal from '../components/FormModal.vue';import ConfirmDialog from '../components/ConfirmDialog.vue';import { ArrowPathIcon, ExclamationTriangleIcon } from '@heroicons/vue/24/outline';export default {name:'Promotions',components:{ModernMetricCard,SearchBar,DataTable,FormModal,ConfirmDialog,ArrowPathIcon,ExclamationTriangleIcon},setup(){const {loading,error,makeRequest}=useApi();const promotions=ref([]);const stats=ref({});const searchTerm=ref('');const activeFilters=ref({});const showFormModal=ref(false);const showDeleteModal=ref(false);const selectedPromotion=ref(null);const promotionToDelete=ref(null);const saveLoading=ref(false);const deleteLoading=ref(false);const columns=[{key:'id',label:'ID',sortable:true},{key:'name',label:'Name',sortable:true},{key:'headline',label:'Headline',sortable:true},{key:'package_name',label:'Package',sortable:true},{key:'is_active',label:'Status',sortable:true},{key:'views',label:'Views',sortable:true},{key:'clicks',label:'Clicks',sortable:true}];const filters=[{key:'is_active',label:'Status',options:[{value:'true',label:'Active'},{value:'false',label:'Inactive'}]}];const formFields=[{key:'name',label:'Promotion Name',type:'text',required:true},{key:'headline',label:'Headline',type:'text',required:true},{key:'description',label:'Description',type:'textarea',rows:3},{key:'button_text',label:'Button Text',type:'text',default:'Get Offer'},{key:'display_order',label:'Display Order',type:'number',min:0},{key:'is_active',label:'Active',type:'checkbox',checkboxLabel:'Promotion is active'}];const filteredPromotions=computed(()=>{let result=promotions.value;if(searchTerm.value){const term=searchTerm.value.toLowerCase();result=result.filter(p=>p.name?.toLowerCase().includes(term)||p.headline?.toLowerCase().includes(term))}Object.keys(activeFilters.value).forEach(key=>{const value=activeFilters.value[key];if(value)result=result.filter(p=>p[key]===(value==='true'))});return result});const fetchPromotions=async()=>{try{const data=await makeRequest('get','promotions/');promotions.value=data.results||data}catch(err){console.error('Error:',err)}};const fetchStats=async()=>{try{stats.value=await makeRequest('get','promotions/stats/')}catch(err){console.error('Error:',err)}};const refreshData=()=>Promise.all([fetchPromotions(),fetchStats()]);const handleFilterChange=({all})=>{activeFilters.value=all};const clearFilters=()=>{searchTerm.value='';activeFilters.value={}};const openCreateModal=()=>{selectedPromotion.value=null;showFormModal.value=true};const openEditModal=(promotion)=>{selectedPromotion.value={...promotion};showFormModal.value=true};const closeFormModal=()=>{showFormModal.value=false;selectedPromotion.value=null};const savePromotion=async(data)=>{saveLoading.value=true;try{const endpoint=data.id?`promotions/${data.id}/`:'promotions/';const method=data.id?'put':'post';await makeRequest(method,endpoint,data);await refreshData();closeFormModal()}catch(err){alert('Error: '+(err.response?.data?.error||err.message))}finally{saveLoading.value=false}};const openDeleteModal=(promotion)=>{promotionToDelete.value=promotion;showDeleteModal.value=true};const closeDeleteModal=()=>{showDeleteModal.value=false;promotionToDelete.value=null};const confirmDelete=async()=>{deleteLoading.value=true;try{await makeRequest('delete',`promotions/${promotionToDelete.value.id}/`);await refreshData();closeDeleteModal()}catch(err){alert('Error: '+(err.response?.data?.error||err.message))}finally{deleteLoading.value=false}};onMounted(refreshData);return{loading,error,promotions,stats,searchTerm,showFormModal,showDeleteModal,selectedPromotion,promotionToDelete,saveLoading,deleteLoading,columns,filters,formFields,filteredPromotions,fetchPromotions,refreshData,handleFilterChange,clearFilters,openCreateModal,openEditModal,closeFormModal,savePromotion,openDeleteModal,closeDeleteModal,confirmDelete}}}</script>
